I created a simple asp.net core webapi application using .net core 2.0 preview 2. It is almost the generated sample project generated by the dotnet wepapi command. All this simple applications does is to return a list of 1.000.000 instances. Those 1 million instances are fix and only generated once.

SAMPLE CODE USED
---------------------------------------------------------------------------------------------------

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;

namespace print.Controllers
{
    [Route("api/[controller]")]
    public class PrintController : Controller
    {
        private PrintOutList list = null;

        // GET api/values
        [HttpGet]
        public IActionResult Get()
        {
            if (list == null)
            {
                list = new PrintOutList();
                list.Build(1000000);
            }
            return new OkObjectResult(list);
        }            
    }

    public enum Weekday
    {
        Monday = 1,
        Tuesday = 2,
        Wednesday = 3
    }

    public class PrintOut
    {
        public string Id { get; set; }
        public int ActorObjectTypeId { get;set;}
        public string ActorId { get; set;}
        public int PrintObjectTypeId { get ; set ;}
        public string PrintObjectId { get; set;}
        public string Text { get; set;}
        public Weekday Weekday { get; set; }
    }

    public class PrintOutList : List<PrintOut>
    {
        public void Build(int  count)
        {
            for(int index=0;index<count;index++)
            {
                PrintOut element = new PrintOut();

                if (index == 0) element.Id = "4711";
                else element.Id = Guid.NewGuid().ToString();
                element.ActorObjectTypeId = 100;
                element.ActorId = Guid.NewGuid().ToString();
                element.PrintObjectTypeId = 200;
                element.PrintObjectId = Guid.NewGuid().ToString();
                element.Text = "This is just a sample. " + index.ToString();
                element.Weekday = Weekday.Monday;
                Add(element);
            }

        }
    }
}

---------------------------------------------------------------------------------------------------

I created a simple asp.net core webapi application using .net core 2.0 preview 2. It is almost the generated sample project generated by the dotnet wepapi command. All this simple applications does is to return a list of 1.000.000 instances. Those 1 million instances are fix and only generated once.

using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;

namespace print.Controllers
{
    [Route("api/[controller]")]
    public class PrintController : Controller
    {
        private PrintOutList list = null;

        // GET api/values
        [HttpGet]
        public IActionResult Get()
        {
            if (list == null)
            {
                list = new PrintOutList();
                list.Build(1000000);
            }
            return new OkObjectResult(list);
        }            
    }

    public enum Weekday
    {
        Monday = 1,
        Tuesday = 2,
        Wednesday = 3
    }

    public class PrintOut
    {
        public string Id { get; set; }
        public int ActorObjectTypeId { get;set;}
        public string ActorId { get; set;}
        public int PrintObjectTypeId { get ; set ;}
        public string PrintObjectId { get; set;}
        public string Text { get; set;}
        public Weekday Weekday { get; set; }
    }

    public class PrintOutList : List<PrintOut>
    {
        public void Build(int  count)
        {
            for(int index=0;index<count;index++)
            {
                PrintOut element = new PrintOut();

                if (index == 0) element.Id = "4711";
                else element.Id = Guid.NewGuid().ToString();
                element.ActorObjectTypeId = 100;
                element.ActorId = Guid.NewGuid().ToString();
                element.PrintObjectTypeId = 200;
                element.PrintObjectId = Guid.NewGuid().ToString();
                element.Text = "This is just a sample. " + index.ToString();
                element.Weekday = Weekday.Monday;
                Add(element);
            }

        }
    }
}


